        def calcul_score_admin(alertes_list):
            score = 0
            for al in alertes_list:
                base = 10
                urgence_bonus = {"Critique": 40, "Élevé": 25, "Modéré": 15, "Faible": 5}.get(al.get("urgence","Faible"), 5)
                desc_bonus = min(20, len(al.get("description","")) // 10)
                action_bonus = 10 if al.get("actions","").strip() else 0
                pop_bonus = min(15, al.get("nb_personnes", 0) // 50)
                score += base + urgence_bonus + desc_bonus + action_bonus + pop_bonus
            return score

