    c1,c2,c3,c4 = st.columns(4)
    q1 = c1.button('⭐ Meilleures zones', use_container_width=True)
    q2 = c2.button('🏥 Déserts médicaux', use_container_width=True)
    q3 = c3.button('🛒 Déserts commerciaux', use_container_width=True)
    q4 = c4.button('⚠️ Signaux faibles', use_container_width=True)
    col1,col2 = st.columns([5,1])
    with col1: question = st.text_input('', placeholder="Posez n'importe quelle question sur les communes...", label_visibility='collapsed')
    with col2: envoyer = st.button('Envoyer', use_container_width=True)
    if q1: question="Quelles sont les meilleures zones pour implanter une entreprise ?"; envoyer=True
    if q2: question='Quelles communes sont en désert médical ?'; envoyer=True
    if q3: question='Quelles communes manquent de commerces ?'; envoyer=True
    if q4: question='Quelles communes montrent les signaux de fragilité les plus forts ?'; envoyer=True
    if envoyer and question:
        st.session_state.messages.append({'role':'user','content':question})
        with st.spinner('Analyse en cours...'):
            try:
                msgs_api = [{'role':'system','content':get_data_summary()}]
                for msg in st.session_state.messages:
                    msgs_api.append({'role':msg['role'],'content':msg['content']})

                if USE_MISTRAL and MistralClient and MISTRAL_API_KEY != 'VOTRE_CLE_MISTRAL_ICI':
                    # Mistral AI
                    client = MistralClient(api_key=MISTRAL_API_KEY)
                    response = client.chat.complete(
                        model='mistral-small-latest',
                        messages=msgs_api,
                        max_tokens=600,
                        temperature=0.7
                    )
                    reponse = response.choices[0].message.content
                elif Groq and GROQ_API_KEY:
                    # Fallback Groq
                    client = Groq(api_key=GROQ_API_KEY)
                    response = client.chat.completions.create(
                        model='llama-3.3-70b-versatile',
                        messages=msgs_api,
                        max_tokens=600,
                        temperature=0.7
                    )
                    reponse = response.choices[0].message.content
                else:
                    reponse = '❌ Aucune clé API configurée. Ajoutez votre clé Mistral ou Groq dans app.py'
            except Exception as e:
                reponse = f'❌ Erreur : {str(e)}'
        st.session_state.messages.append({'role':'assistant','content':reponse})
        st.rerun()